dslRule:
/*!id: jdt.internal.javadoc.textelement-to-abstracttextelement.type-replace*/
/*!description: Replaces references to TextElement with AbstractTextElement in JDT internal Javadoc snippet evaluation. This is a type widening/modernization for internal AST types.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
org.eclipse.jdt.core.dom.TextElement
=> org.eclipse.jdt.core.dom.AbstractTextElement
;;

/*!id: jdt.internal.javadoc.textelement-to-abstracttextelement.instanceof-replace*/
/*!description: Replaces instanceof checks for TextElement with AbstractTextElement in JDT internal Javadoc snippet evaluation.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
$fragment instanceof org.eclipse.jdt.core.dom.TextElement
=> $fragment instanceof org.eclipse.jdt.core.dom.AbstractTextElement
;;

/*!id: jdt.internal.javadoc.textelement-to-abstracttextelement.cast-replace*/
/*!description: Replaces casts to TextElement with AbstractTextElement in JDT internal Javadoc snippet evaluation.*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: jdt, internal, refactoring*/
(org.eclipse.jdt.core.dom.TextElement) $fragment
=> (org.eclipse.jdt.core.dom.AbstractTextElement) $fragment
;;

/*!id: jdt.internal.cleanup.remove-redundant-ancestor-cast.statement*/
/*!description: Removes redundant (Statement) cast from ASTNodes.getFirstAncestorOrNull when the variable is already declared as Statement.*/
/*!severity: info*/
(org.eclipse.jdt.core.dom.Statement) org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.Statement.class)
=> org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.Statement.class)
;;

/*!id: jdt.internal.cleanup.remove-redundant-ancestor-cast.variabledeclarationstatement*/
/*!description: Removes redundant (VariableDeclarationStatement) cast from ASTNodes.getFirstAncestorOrNull when the variable is already declared as VariableDeclarationStatement.*/
/*!severity: info*/
(org.eclipse.jdt.core.dom.VariableDeclarationStatement) org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.VariableDeclarationStatement.class)
=> org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.VariableDeclarationStatement.class)
;;

/*!id: jdt.internal.cleanup.remove-redundant-ancestor-cast.fielddeclaration*/
/*!description: Removes redundant (FieldDeclaration) cast from ASTNodes.getFirstAncestorOrNull when the variable is already declared as FieldDeclaration.*/
/*!severity: info*/
(org.eclipse.jdt.core.dom.FieldDeclaration) org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.FieldDeclaration.class)
=> org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.FieldDeclaration.class)
;;

/*!id: jdt.internal.cleanup.refine-local-variable-type.assignment*/
/*!description: Refines local variable declaration type from ASTNode to Assignment when the initializer is ASTNodes.getFirstAncestorOrNull(..., Assignment.class).*/
/*!severity: info*/
org.eclipse.jdt.core.dom.ASTNode $assignNode = org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.Assignment.class);
=> org.eclipse.jdt.core.dom.Assignment $assignNode = org.eclipse.jdt.internal.corext.dom.ASTNodes.getFirstAncestorOrNull($node, org.eclipse.jdt.core.dom.Assignment.class);
;;

/*!id: jdt.internal.browser.location.aboutblank-to-dataurl*/
/*!description: Extends the 'about:blank' location check to include 'data:' URLs for Edge browser compatibility when setText() is used. This fixes an internal JDT UI bug. (Pattern 1 of 2)*/
/*!severity: error*/
"about:blank".equals($locVar) :: instanceof($locVar, "java.lang.String")
=> "about:blank".equals($locVar) || $locVar.startsWith("data:")
;;

/*!id: jdt.internal.browser.location.external-link-guard*/
/*!description: Adds a guard for 'data:' URLs when handling external links in the browser to prevent incorrect processing for Edge browser setText() calls. This fixes an internal JDT UI bug. (Pattern 2 of 2)*/
/*!severity: error*/
$handler.handleExternalLink(new java.net.URL($locVar), $eventDisplay) :: instanceof($locVar, "java.lang.String")
=> !$locVar.startsWith("data:") && $handler.handleExternalLink(new java.net.URL($locVar), $eventDisplay)
;;

/*!id: jdt.internal.refactor.java50fix.fqn-rename-method-calls*/
/*!description: Renames static method calls from Java50Fix to Java50FixCore following internal JDT refactoring.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.Java50Fix.$method($args$)
=> org.eclipse.jdt.internal.corext.fix.Java50FixCore.$method($args$)
;;

/*!id: jdt.internal.refactor.java50fix.createcleanup-wrap-with-wrapper*/
/*!description: Wraps calls to Java50FixCore.createCleanUp with CleanUpFixWrapper to align with internal JDT cleanup API structure.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.Java50FixCore.createCleanUp($compilationUnit, $addOverride, $addOverrideInterfaceMethods, $addMissingDeprecated, $useTypeArgs)
=> new org.eclipse.jdt.internal.ui.fix.CleanUpFixWrapper(org.eclipse.jdt.internal.corext.fix.Java50FixCore.createCleanUp($compilationUnit, $addOverride, $addOverrideInterfaceMethods, $addMissingDeprecated, $useTypeArgs))
;;

/*!id: jdt.internal.refactor.java50fix.add-problemlocationcore-cast*/
/*!description: Adds an explicit cast to IProblemLocationCore for problem arguments in internal JDT fix creation methods.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.Java50FixCore.createRawTypeReferenceFix($astRoot, $problem)
=> org.eclipse.jdt.internal.corext.fix.Java50FixCore.createRawTypeReferenceFix($astRoot, (org.eclipse.jdt.internal.ui.text.correction.IProblemLocationCore) $problem)
;;

/*!id: jdt.internal.refactor.codesytlefix.add-problemlocationcore-cast-indirect*/
/*!description: Adds an explicit cast to IProblemLocationCore for problem arguments in CodeStyleFixCore.createIndirectAccessToStaticFix.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.CodeStyleFixCore.createIndirectAccessToStaticFix($astRoot, $problem)
=> org.eclipse.jdt.internal.corext.fix.CodeStyleFixCore.createIndirectAccessToStaticFix($astRoot, (org.eclipse.jdt.internal.ui.text.correction.IProblemLocationCore) $problem)
;;

/*!id: jdt.internal.refactor.codesytlefix.add-problemlocationcore-cast-nonstatic*/
/*!description: Adds an explicit cast to IProblemLocationCore for problem arguments in CodeStyleFixCore.createNonStaticAccessFixes.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.CodeStyleFixCore.createNonStaticAccessFixes($astRoot, $problem)
=> org.eclipse.jdt.internal.corext.fix.CodeStyleFixCore.createNonStaticAccessFixes($astRoot, (org.eclipse.jdt.internal.ui.text.correction.IProblemLocationCore) $problem)
;;

@id: javadoc.handlecontentelements.callsite.add-null-arg
@severity: info
this.handleContentElements($nodes, false) :: inClass("org.eclipse.jdt.internal.ui.text.javadoc.JavadocContentAccess2") && inMethod("handleContentElements")
=> this.handleContentElements($nodes, false, null)
;;

@id: javadoc.handlecontentelements.callsite.add-node-arg
@severity: info
handleContentElements(node.fragments(), true) :: inClass("org.eclipse.jdt.internal.ui.text.javadoc.JavadocContentAccess2") && inMethod("handleInlineTagElement")
=> handleContentElements(node.fragments(), true, node)
;;
